  connections
    ACC_INPUT_PC1   : port acc_in_data_x	-> accelero_thread.acc_in_data_x;
    ACC_INPUT_PC2   : port acc_in_data_y	-> accelero_thread.acc_in_data_y;
    ACC_INPUT_PC3   : port acc_in_data_z	-> accelero_thread.acc_in_data_z;

